const requestData = $('Unpack AI Agent Instruction1').first().json;
const context = $input.first().json || {};

const sourceImageUrl =
  requestData.request_body.image_url ||
  requestData.request_body.start_image_url ||
  requestData.source_image_url ||
  context.last_image_url ||
  '';

if (
  (requestData.generation_mode === 'image_to_image' ||
   requestData.generation_mode === 'image_to_video') &&
  !sourceImageUrl
) {
  throw new Error('This request requires a source image, but none was found.');
}

const requestBody = { ...requestData.request_body };

if (requestData.generation_mode === 'image_to_image' && !requestBody.image_url) {
  requestBody.image_url = sourceImageUrl;
}

if (
  requestData.generation_mode === 'image_to_video' &&
  !requestBody.image_url &&
  !requestBody.start_image_url
) {
  requestBody.image_url = sourceImageUrl;
}

return [
  {
    json: {
      ...requestData,
      request_body: requestBody
    }
  }
];

const data = $input.first().json;
const status = String(data.status || '').toUpperCase();

if (['FAILED', 'ERROR', 'CANCELLED', 'CANCELED'].includes(status)) {
  throw new Error(`fal video generation failed with status: ${status}`);
}

return [{ json: data }];

let data = $input.first()?.json;

function unwrapPayload(value) {
  let current = value;
  while (Array.isArray(current) && current.length > 0) {
    const first = current[0];
    current = first && typeof first === 'object' && 'json' in first ? first.json : first;
  }
  return current && typeof current === 'object' ? current : {};
}

data = unwrapPayload(data);

function parseJsonValue(value) {
  if (!value) return null;
  if (typeof value === 'object') return value;
  if (typeof value !== 'string') return null;
  try {
    return JSON.parse(value);
  } catch {
    return null;
  }
}

function parseTaggedJson(text, tagName) {
  if (typeof text !== 'string' || !text.trim()) return null;
  const prefix = `[${tagName}:`;
  const start = text.indexOf(prefix);
  if (start === -1) return null;
  const afterPrefix = text.slice(start + prefix.length).trimStart();
  // Find matching braces instead of looking for ] — avoids false matches
  // on ] characters inside the JSON (e.g. "images[0].url", array values)
  const braceStart = afterPrefix.indexOf('{');
  if (braceStart === -1) return null;
  let depth = 0;
  let braceEnd = -1;
  for (let i = braceStart; i < afterPrefix.length; i++) {
    if (afterPrefix[i] === '{') depth++;
    else if (afterPrefix[i] === '}') {
      depth--;
      if (depth === 0) { braceEnd = i; break; }
    }
  }
  if (braceEnd === -1) return null;
  return parseJsonValue(afterPrefix.slice(braceStart, braceEnd + 1));
}

function parseLegacyJson(text) {
  if (typeof text !== 'string' || !text.trim()) return null;
  const matches = text.match(/\{(?:[^{}]|\{[^{}]*\})*\}/g) || [];
  for (const raw of matches) {
    try {
      const parsed = JSON.parse(raw);
      if (parsed.fal_model_endpoint && parsed.fal_input) {
        return { endpoint: parsed.fal_model_endpoint, input: parsed.fal_input };
      }
    } catch (_) {}
  }
  return null;
}

function inferMode(request) {
  if (request.generation_mode) return request.generation_mode;
  const endpoint = request.endpoint || '';
  const input = request.input || {};
  const hasImage = !!input.image_url || !!input.start_image_url || !!request.requires_source_image;
  if (endpoint.includes('/image-to-video')) return 'image_to_video';
  if (endpoint.includes('/text-to-video')) return 'text_to_video';
  if (hasImage) return 'image_to_image';
  return 'text_to_image';
}

// FIRST: Check for structured data from table_1 Classifier
let request = null;

if (data.gen_mode && data.gen_prompt) {
  // Build request from table_2 fields
  const generationMode = data.gen_mode;
  const mediaType = generationMode.includes('video') ? 'video' : 'image';
  const transport = mediaType === 'video' ? 'queue' : 'sync';
  const endpoint = generationMode === 'text_to_image' 
    ? 'fal-ai/flux-2-pro'
    : generationMode === 'image_to_image'
      ? 'fal-ai/flux-2-pro/edit'
      : generationMode === 'text_to_video'
        ? 'fal-ai/kling-video/v3/standard/text-to-video'
        : 'fal-ai/kling-video/v3/standard/image-to-video';

  request = {
    endpoint: endpoint,
    generation_mode: generationMode,
    media_type: mediaType,
    transport: transport,
    response_path: mediaType === 'video' ? 'video.url' : 'images[0].url',
    input: {
      prompt: data.gen_prompt,
      image_size: mediaType === 'image' ? 'square_hd' : undefined
    }
  };

  // Add source image URL for image-based generation
  // Priority: data.image_id → FAL tag embedded URL → nothing
  const falTagRequest = parseTaggedJson(data.output, 'FAL_MEDIA_REQUEST');

  if (generationMode === 'image_to_image') {
    const urlFromTag = falTagRequest?.input?.image_urls?.[0] || falTagRequest?.input?.image_url || null;
    const sourceUrl = data.image_id || urlFromTag || '';
    if (sourceUrl) request.input.image_urls = [sourceUrl];
  }
  if (generationMode === 'image_to_video') {
    const urlFromTag = falTagRequest?.input?.start_image_url || falTagRequest?.input?.image_url || null;
    const sourceUrl = data.image_id || urlFromTag || '';
    if (sourceUrl) request.input.start_image_url = sourceUrl;
  }
}
// SECOND: Try to parse from table_3 field
else {
  request =
    parseJsonValue(data.fal_request) ||
    parseTaggedJson(data.output, 'FAL_MEDIA_REQUEST') ||
    parseLegacyJson(data.output) ||
    parseLegacyJson(data.gen_prompt);
}

if (!request) {
  throw new Error('No valid fal request found in input payload.');
}

const endpointMap = {
  text_to_image:  'fal-ai/flux-2-pro',
  image_to_image: 'fal-ai/flux-2-pro/edit',
  text_to_video:  'fal-ai/kling-video/v3/standard/text-to-video',
  image_to_video: 'fal-ai/kling-video/v3/standard/image-to-video'
};
const endpoint = request.endpoint || request.fal_model_endpoint || endpointMap[generationMode] || null;
if (!endpoint) {
  throw new Error('fal request is missing endpoint.');
}

const generationMode = inferMode(request);
const mediaType = request.media_type || (generationMode.includes('video') ? 'video' : 'image');
const transport = request.transport || (mediaType === 'video' ? 'queue' : 'sync');
const input = { ...(request.input || request.fal_input || {}) };

const sourceImageUrl =
  data.source_image_url ||
  data.image_id ||
  input.image_urls?.[0] ||
  input.start_image_url ||
  '';

if ((generationMode === 'image_to_image' || generationMode === 'image_to_video') && !sourceImageUrl) {
  throw new Error('This request requires a source image URL, but none was provided.');
}

if (generationMode === 'image_to_image' && sourceImageUrl && !input.image_url && !input.image_urls) {
  input.image_urls = [sourceImageUrl];
}

if (generationMode === 'image_to_video' && sourceImageUrl && !input.image_url && !input.start_image_url) {
  input.start_image_url = sourceImageUrl;
}

if (!input.prompt && data.gen_prompt) {
  input.prompt = data.gen_prompt;
}

if (!input.prompt) {
  throw new Error('fal request input is missing prompt.');
}

const submitUrl = transport === 'queue'
  ? `[URL]
  : `[URL]

return [{
  json: {
    output: data.output || '',
    telegram_id: data.telegram_id || '',
    phone_no: data.phone_no || '',
    caption: data.caption || '',
    source: data.source || '',
    image_id: data.image_id || '',
    gen_prompt: data.gen_prompt || input.prompt || '',
    endpoint,
    generation_mode: generationMode,
    media_type: mediaType,
    transport,
    submit_url: submitUrl,
    response_path: request.response_path || (mediaType === 'video' ? 'video.url' : 'images[0].url'),
    request_body: input,
    source_image_url: sourceImageUrl || ''
  }
}];

const data = $input.first().json;

return [{
  json: {
    ...data,
    fal_url: data.submit_url,
    is_async: data.transport === 'queue'
  }
}];

// Handle the response: extract request_id if async, or media_url if sync
const response = $input.first().json;
const prevData = $('Route to Sync or Async1').first().json;

let mediaUrl = null;
let requestId = null;
let statusUrl = null;

if (prevData.is_async) {
  // Async response (queue-based: Kling, MiniMax video, etc.)
  requestId = response.request_id;
  statusUrl = response.status_url;
  if (!requestId) throw new Error('No request_id in async response: ' + JSON.stringify(response));
} else {
  // Sync response — try all known fal response shapes
  if (response.images && response.images.length > 0) {
    mediaUrl = response.images[0].url;
  } else if (response.image && response.image.url) {
    mediaUrl = response.image.url;
  } else if (response.image_url) {
    mediaUrl = response.image_url;
  } else if (response.url) {
    mediaUrl = response.url;
  } else if (response.output && response.output.url) {
    mediaUrl = response.output.url;
  } else if (response.output && typeof response.output === 'string') {
    mediaUrl = response.output;
  }

  if (!mediaUrl) throw new Error('No media URL in sync response: ' + JSON.stringify(response));
}

return [{
  json: {
    ...prevData,
    is_async: prevData.is_async,
    request_id: requestId,
    status_url: statusUrl,
    media_url: mediaUrl
  }
}];

const inputData = $input.first().json;

let mediaUrl = inputData.media_url || '';

if (!mediaUrl) {
    if (inputData.images && inputData.images[0]) {
        mediaUrl = inputData.images[0].url;
    } else if (inputData.image && inputData.image.url) {
        mediaUrl = inputData.image.url;
    } else if (inputData.video && inputData.video.url) {
        mediaUrl = inputData.video.url;
    } else if (inputData.videos && inputData.videos[0]) {
        mediaUrl = inputData.videos[0].url;
    } else if (inputData.url) {
        mediaUrl = inputData.url;
    } else if (inputData.output && inputData.output.url) {
        mediaUrl = inputData.output.url;
    }
}

if (!mediaUrl) {
    throw new Error('No media_url found in Fal Tool response');
}

let originalRequest = {};
try {
    originalRequest = $('Unpack AI Agent Instruction1').first().json;
} catch (e) {
    originalRequest = inputData;
}

let mediaType = inputData.media_type || originalRequest.media_type;
if (!mediaType) {
    const generationMode = originalRequest.generation_mode || inputData.generation_mode || '';
    mediaType = generationMode.includes('video') ? 'video' : 'image';
}

// Apply Cloudinary watermark
const CLOUD_NAME = 'duiax34k4';
const transform = `l_MySquad_Logo4_qbj7f5,w_70,o_80,g_south_east,x_20,y_20`;

const cloudinaryType = mediaType === 'video' ? 'video' : 'image';
mediaUrl = `[URL] + encodeURIComponent(mediaUrl);

return [{
    json: {
        media_url: mediaUrl,
        media_type: mediaType,
        generation_mode: originalRequest.generation_mode || inputData.generation_mode,
        gen_prompt: originalRequest.gen_prompt || inputData.gen_prompt,
        caption: originalRequest.caption || inputData.caption,
        telegram_id: originalRequest.telegram_id || inputData.telegram_id,
        source: originalRequest.source || inputData.source || 'telegram'
    }
}];
